// Embed the input text using the local embedding service.
// Returns the 384-dim vector formatted as a pgvector literal string,
// ready to paste into a query_db SQL call.
const resp = await this.helpers.httpRequest({
  method: "POST",
  url: "http://127.0.0.1:8001/embed",
  body: { text: query },
  json: true,
});
return JSON.stringify(resp.vector);
